import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, LinearProgress } from '@mui/material';
import response from './response.json';

interface Task {
  task: string;
  priority: string;
  completed: boolean;
}

interface CompletionProgress {
  totalTasks: number;
  tasksCompleted: number;
  completionPercentage: number;
}

interface TaskManagerData {
  todayTasks: Task[];
  completionProgress: CompletionProgress;
}

export default function Widget() {
  const taskManagerData = response.data as TaskManagerData;
  const { todayTasks, completionProgress } = taskManagerData;
  const theme = response.meta.theme;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: theme === 'dark' ? '#263238' : '#FFFFFF',
        color: theme === 'dark' ? '#FFFFFF' : '#000000',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600}>
              Today's Tasks
            </Typography>
            <Stack spacing={1}>
              {todayTasks.map((task, index) => (
                <Stack key={index} direction="row" justifyContent="space-between" alignItems="center">
                  <Typography variant="body2">{task.task}</Typography>
                  <Chip
                    label={task.priority}
                    sx={{
                      bgcolor: task.priority === 'High' ? '#FF5722' : task.priority === 'Medium' ? '#FFC107' : '#8BC34A',
                      color: '#FFFFFF',
                      fontSize: '10px',
                      height: '20px',
                    }}
                  />
                </Stack>
              ))}
            </Stack>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Completion Progress
              </Typography>
              <Typography variant="caption" fontWeight={600}>
                {completionProgress.completionPercentage}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={completionProgress.completionPercentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: theme === 'dark' ? '#37474F' : '#E0E0E0',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#FF5722',
                  borderRadius: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
